// At every single node: everything to the LEFT is smaller, everything to the RIGHT is bigger

bool search(TreeNode *node, int target)
{
    if (node == nullptr) return false; // not found
    if (node->data == target) return true; // found it

    if (target < node->data)
    {
        return search(node->left, target); // go LEFT — smaller values live there
    }
    return search(node->right, target); // go RIGHT — bigger values live there
}

#include <iostream>

using namespace std;

struct TreeNode
{
    int data;
    TreeNode *left;
    TreeNode *right;
};

TreeNode *insert(TreeNode *node, int value)
{
    if (node == nullptr) // found the correct empty spot
    {
        return new TreeNode{value, nullptr, nullptr};
    }

    if (value < node->data)
    {
        node->left = insert(node->left, value);
    }
    else
    {
        node->right = insert(node->right, value);
    }
    return node;
}

bool search(TreeNode *node, int target)
{
    if (node == nullptr) return false;
    if (node->data == target) return true;
    if (target < node->data) return search(node->left, target);
    return search(node->right, target);
}

