using namespace std;

struct TreeNode {
    int val;
    TreeNode *left, *right;
    TreeNode(int x) : val(x), left(nullptr), right(nullptr) {}
};

void collect(TreeNode* node, vector<int> &values)
{
    if (node == nullptr) return;
    collect(node->left, values);
    values.push_back(node->val);
    collect(node->right, values);
}

TreeNode* buildBalanced(vector<int> &values, int lo, int hi)
{
    if (lo > hi) return nullptr;
    int mid = lo + (hi - lo) / 2;
    TreeNode* node = new TreeNode(values[mid]);
    node->left = buildBalanced(values, lo, mid - 1);
    node->right = buildBalanced(values, mid + 1, hi);
    return node;
}

TreeNode* insertIntoBST(TreeNode* root, int val)
{
    vector<int> values;
    collect(root, values);
    values.push_back(val);
    sort(values.begin(), values.end());
    return buildBalanced(values, 0, values.size() - 1);
}

